+/// Insert embedding into LanceDB vectors table
+/// Returns: 0 on success, negative error code on failure
+///   -1: Invalid embedding dimension (must be 384)
+///   -2: Failed to insert
+export fn zell_insert_embedding(
+    table_path: [*:0]const u8,
+    file_path: [*:0]const u8,
+    chunk_id: c_int,
+    content: [*:0]const u8,
+    embedding: [*]const f32,
+    embedding_len: c_int,
+) c_int {
+    const table_path_slice = std.mem.sliceTo(table_path, 0);
+    const file_path_slice = std.mem.sliceTo(file_path, 0);
+    const content_slice = std.mem.sliceTo(content, 0);
+    const embedding_slice = embedding[0..@as(usize, @intCast(embedding_len))];
+
+    if (embedding_len != 384) {
+        std.debug.print("[C API] ERROR: Invalid embedding dimension {}, expected 384\n", .{embedding_len});
+        return -1;
+    }
+
+    embeddings.insertEmbedding(
+        global_allocator,
+        table_path_slice,
+        file_path_slice,
+        @intCast(chunk_id),
+        content_slice,
+        embedding_slice,
+    ) catch |err| {
+        std.debug.print("[C API] ERROR: Failed to insert embedding: {}\n", .{err});
+        return -2;
+    };
+
+    return 0;
+}
