+/// Search for similar embeddings
+/// Returns: number of results found, or negative error code on failure
+///   -1: Invalid embedding dimension (must be 384)
+///   -2: Search failed
+///   -3: Output buffer too small
+///
+/// Results are written to output arrays (preallocated by caller):
+///   - result_file_paths: array of char* (caller must allocate strings)
+///   - result_chunk_ids: array of int
+///   - result_distances: array of float
+export fn zell_search_similar(
+    table_path: [*:0]const u8,
+    query_embedding: [*]const f32,
+    embedding_len: c_int,
+    k: c_int,
+    result_file_paths: [*][*:0]u8,
+    result_chunk_ids: [*]c_int,
+    result_distances: [*]f32,
+) c_int {
+    const table_path_slice = std.mem.sliceTo(table_path, 0);
+    const query_slice = query_embedding[0..@as(usize, @intCast(embedding_len))];
+
+    if (embedding_len != 384) {
+        std.debug.print("[C API] ERROR: Invalid embedding dimension {}, expected 384\n", .{embedding_len});
+        return -1;
+    }
+
+    const results = embeddings.searchSimilar(
+        global_allocator,
+        table_path_slice,
+        query_slice,
+        @intCast(k),
+    ) catch |err| {
+        std.debug.print("[C API] ERROR: Search failed: {}\n", .{err});
+        return -2;
+    };
+    defer {
+        for (results) |result| {
+            result.deinit(global_allocator);
+        }
+        global_allocator.free(results);
+    }
+
+    // Copy results to output arrays
+    for (results, 0..) |result, i| {
+        // Allocate and copy file path (caller must free)
+        const path_copy = global_allocator.dupeZ(u8, result.file_path) catch {
+            std.debug.print("[C API] ERROR: Failed to allocate result string\n", .{});
+            return -2;
+        };
+        result_file_paths[i] = path_copy.ptr;
+        result_chunk_ids[i] = @intCast(result.chunk_id);
+        result_distances[i] = result.distance;
+    }
+
+    return @intCast(results.len);
+}
