+/// Embedding vector (384-dim for MiniLM)
+pub const Embedding = struct {
+    data: []f32,
+    allocator: std.mem.Allocator,
+
+    pub fn init(allocator: std.mem.Allocator) !Embedding {
+        const data = try allocator.alloc(f32, 384);
+        return .{
+            .data = data,
+            .allocator = allocator,
