+/// Insert embedding into vectors database
+///
+/// For now, stores in simple JSONL format (one JSON object per line).
+/// Format: {"path":"file.zig","chunk":0,"content":"...","embedding":[...]}
+///
+/// TODO: Upgrade to Lance format when lanceql write API is available.
+pub fn insertEmbedding(
+    _: std.mem.Allocator, // allocator not used yet
+    table_path: []const u8,
+    file_path: []const u8,
+    chunk_id: u32,
+    content: []const u8,
+    embedding: []const f32,
+) !void {
+    if (embedding.len != 384) {
+        return error.InvalidEmbeddingDimension;
+    }
+
+    // Ensure data directory exists
+    const dir_path = std.fs.path.dirname(table_path) orelse ".";
+    std.fs.cwd().makePath(dir_path) catch {}; // Ignore if exists
+
+    // Open file for appending (create if doesn't exist)
+    var file = try std.fs.cwd().createFile(table_path, .{
+        .read = true,
+        .truncate = false, // Append mode
+    });
+    defer file.close();
+
+    // Seek to end for appending
+    try file.seekFromEnd(0);
+
+    // Build JSONL string in memory then write
+    var json_buf = std.ArrayList(u8){};
+    defer json_buf.deinit(std.heap.page_allocator);
+
+    var json_writer = json_buf.writer(std.heap.page_allocator);
+
+    // Start JSON object
+    try json_writer.writeAll("{\"path\":\"");
+    try writeJsonEscaped(json_writer, file_path);
+    try json_writer.writeAll("\",\"chunk\":");
+    try json_writer.print("{}", .{chunk_id});
+    try json_writer.writeAll(",\"content\":\"");
+    try writeJsonEscaped(json_writer, content);
+    try json_writer.writeAll("\",\"embedding\":[");
+
+    // Write embedding vector
+    for (embedding, 0..) |val, i| {
+        if (i > 0) try json_writer.writeAll(",");
+        try json_writer.print("{d:.6}", .{val});
+    }
+
+    try json_writer.writeAll("]}\n");
+
+    // Write to file
+    try file.writeAll(json_buf.items);
+
+    std.debug.print("[embeddings] Stored: {s} chunk {}\n", .{ file_path, chunk_id });
+}
+
+/// Escape special JSON characters
+fn writeJsonEscaped(writer: anytype, text: []const u8) !void {
+    for (text) |c| {
+        switch (c) {
+            '"' => try writer.writeAll("\\\""),
+            '\\' => try writer.writeAll("\\\\"),
+            '\n' => try writer.writeAll("\\n"),
+            '\r' => try writer.writeAll("\\r"),
+            '\t' => try writer.writeAll("\\t"),
+            else => if (c < 32) {
+                try writer.print("\\u{x:0>4}", .{c});
+            } else {
+                try writer.writeByte(c);
+            },
+        }
+    }
+}
