+/// Search for similar embeddings using vector similarity
+///
+/// Returns top-k most similar code snippets based on cosine distance.
+/// For now, does linear scan - TODO: add vector index (HNSW/IVF) when lanceql supports it.
+pub fn searchSimilar(
+    allocator: std.mem.Allocator,
+    table_path: []const u8,
+    query_embedding: []const f32,
+    k: u32,
+) ![]SearchResult {
+    if (query_embedding.len != 384) {
+        return error.InvalidEmbeddingDimension;
+    }
+
+    // Check if file exists
+    const file = std.fs.cwd().openFile(table_path, .{}) catch {
+        // No embeddings yet, return empty
+        return try allocator.alloc(SearchResult, 0);
+    };
+    defer file.close();
+
+    // Read file and parse JSONL
+    const file_size = (try file.stat()).size;
+    if (file_size == 0) {
+        return try allocator.alloc(SearchResult, 0);
+    }
+
+    const content = try file.readToEndAlloc(allocator, 100 * 1024 * 1024); // Max 100MB
+    defer allocator.free(content);
+
+    // Parse each line and compute similarity
+    var candidates = std.ArrayList(struct {
+        path: []const u8,
+        chunk_id: u32,
+        content_text: []const u8,
+        distance: f32,
+    }){};
+    defer candidates.deinit(allocator);
+
+    var lines = std.mem.splitScalar(u8, content, '\n');
+    while (lines.next()) |line| {
+        if (line.len == 0) continue;
+
+        // Parse JSON (simple parsing - just extract embedding array)
+        const embedding_start = std.mem.indexOf(u8, line, "\"embedding\":[") orelse continue;
+        const embedding_end = std.mem.indexOfPos(u8, line, embedding_start, "]}") orelse continue;
+
+        const embedding_json = line[embedding_start + 13 .. embedding_end];
+
+        // Parse embedding values
+        var embedding: [384]f32 = undefined;
+        var idx: usize = 0;
+        var values = std.mem.splitScalar(u8, embedding_json, ',');
+        while (values.next()) |val_str| : (idx += 1) {
+            if (idx >= 384) break;
+            embedding[idx] = std.fmt.parseFloat(f32, std.mem.trim(u8, val_str, " ")) catch 0.0;
+        }
+
+        if (idx != 384) continue; // Invalid embedding
+
+        // Compute cosine distance
+        const distance = cosineDist(&embedding, query_embedding);
+
+        // Extract metadata
+        const path = extractJsonString(line, "path") orelse continue;
+        const chunk_id = extractJsonInt(line, "chunk") orelse 0;
+        const content_text = extractJsonString(line, "content") orelse "";
+
+        try candidates.append(allocator, .{
+            .path = path,
+            .chunk_id = chunk_id,
+            .content_text = content_text,
+            .distance = distance,
+        });
+    }
+
+    // Sort by distance (ascending - lower is more similar)
+    std.mem.sort(@TypeOf(candidates.items[0]), candidates.items, {}, struct {
+        fn lessThan(_: void, a: @TypeOf(candidates.items[0]), b: @TypeOf(candidates.items[0])) bool {
+            return a.distance < b.distance;
+        }
+    }.lessThan);
+
+    // Return top-k results
+    const num_results = @min(k, @as(u32, @intCast(candidates.items.len)));
+    const results = try allocator.alloc(SearchResult, num_results);
+
+    for (0..num_results) |i| {
+        const candidate = candidates.items[i];
+        results[i] = .{
+            .file_path = try allocator.dupe(u8, candidate.path),
+            .chunk_id = candidate.chunk_id,
+            .content = try allocator.dupe(u8, candidate.content_text),
+            .distance = candidate.distance,
+        };
+    }
+
+    std.debug.print("[embeddings] searchSimilar: found {} results\n", .{num_results});
+    return results;
+}
+
+/// Compute cosine distance (1 - cosine similarity)
+fn cosineDist(a: []const f32, b: []const f32) f32 {
+    var dot: f32 = 0.0;
+    var norm_a: f32 = 0.0;
+    var norm_b: f32 = 0.0;
+
+    for (a, b) |va, vb| {
+        dot += va * vb;
+        norm_a += va * va;
+        norm_b += vb * vb;
+    }
+
+    const norm = @sqrt(norm_a * norm_b);
+    if (norm < 0.000001) return 1.0; // Avoid division by zero
+
+    return 1.0 - (dot / norm);
+}
