+/// Extract JSON string value (simple parser)
+fn extractJsonString(line: []const u8, key: []const u8) ?[]const u8 {
+    var search_buf: [128]u8 = undefined;
+    const search_key = std.fmt.bufPrint(&search_buf, "\"{s}\":\"", .{key}) catch return null;
+
+    const start_idx = std.mem.indexOf(u8, line, search_key) orelse return null;
+    const value_start = start_idx + search_key.len;
+
+    // Find closing quote (handle escaped quotes)
+    var i = value_start;
+    while (i < line.len) : (i += 1) {
+        if (line[i] == '"' and (i == value_start or line[i - 1] != '\\')) {
+            return line[value_start..i];
+        }
+    }
+
+    return null;
+}
+
+/// Extract JSON integer value (simple parser)
+fn extractJsonInt(line: []const u8, key: []const u8) ?u32 {
+    var search_buf: [128]u8 = undefined;
+    const search_key = std.fmt.bufPrint(&search_buf, "\"{s}\":", .{key}) catch return null;
+
+    const start_idx = std.mem.indexOf(u8, line, search_key) orelse return null;
+    const value_start = start_idx + search_key.len;
+
+    // Find next comma or closing brace
+    const value_end = std.mem.indexOfAnyPos(u8, line, value_start, ",}") orelse line.len;
+    const value_str = std.mem.trim(u8, line[value_start..value_end], " ");
+
+    return std.fmt.parseInt(u32, value_str, 10) catch null;
+}
